create extension if not exists pgcrypto;
create table public.assessment_settings(id uuid primary key default gen_random_uuid(),singleton_key boolean not null default true unique check(singleton_key),assessment_title text not null default 'I Know Your Works',is_open boolean not null default true,questions_per_attempt integer not null default 30 check(questions_per_attempt between 1 and 40),duration_minutes integer check(duration_minutes between 1 and 480),show_scores_on_activity boolean not null default false,show_score_to_student boolean not null default true,updated_at timestamptz not null default now());
insert into public.assessment_settings(singleton_key,duration_minutes) values(true,30);
create table public.classes(id uuid primary key default gen_random_uuid(),name text not null unique,is_active boolean not null default true,created_at timestamptz not null default now());
insert into public.classes(name) values('Righteousness class'),('Peace Class'),('Joy');
create table public.questions(id uuid primary key default gen_random_uuid(),question_number integer not null unique,lesson_title text,question_text text not null,is_active boolean not null default true,created_at timestamptz not null default now());
create table public.question_options(id uuid primary key default gen_random_uuid(),question_id uuid not null references public.questions(id) on delete cascade,option_key text not null,option_text text not null,is_correct boolean not null default false,unique(question_id,option_key));
create unique index exactly_one_correct_option on public.question_options(question_id) where is_correct;
create table public.attempts(id uuid primary key default gen_random_uuid(),public_token uuid not null default gen_random_uuid() unique,student_name text not null,class_name_snapshot text not null,status text not null default 'in_progress' check(status in('in_progress','submitted','abandoned')),started_at timestamptz not null default now(),deadline_at timestamptz,duration_limit_minutes integer,last_activity_at timestamptz,submitted_at timestamptz,total_questions integer not null,answered_count integer not null default 0,correct_count integer,incorrect_count integer,unanswered_count integer,score_percentage numeric(5,2),standing text,duration_seconds integer,auto_submitted boolean not null default false,created_at timestamptz not null default now());
create table public.attempt_questions(id uuid primary key default gen_random_uuid(),attempt_id uuid not null references public.attempts(id) on delete cascade,question_id uuid not null references public.questions(id),display_order integer not null,option_order jsonb not null,unique(attempt_id,display_order),unique(attempt_id,question_id));
create table public.attempt_answers(id uuid primary key default gen_random_uuid(),attempt_id uuid not null references public.attempts(id) on delete cascade,attempt_question_id uuid not null references public.attempt_questions(id) on delete cascade,selected_option_id uuid references public.question_options(id),answered_at timestamptz,created_at timestamptz not null default now(),unique(attempt_id,attempt_question_id));
alter table public.assessment_settings enable row level security;alter table public.classes enable row level security;alter table public.questions enable row level security;alter table public.question_options enable row level security;alter table public.attempts enable row level security;alter table public.attempt_questions enable row level security;alter table public.attempt_answers enable row level security;
revoke all on all tables in schema public from anon,authenticated;
alter publication supabase_realtime add table public.attempts,public.assessment_settings;
